PARAMETER_LIST PL_TestConfig
VAR_GLOBAL CONSTANT
    c_udiMaxTests : UDINT := 40;
END_VAR
END_PARAMETER_LIST

TYPE E_TestState :
(
    eTestState_Idle := 0,
    eTestState_Running := 1,
    eTestState_Passed := 2,
    eTestState_Failed := 3,
    eTestState_Error := 4,
    eTestState_Skipped := 5
);
END_TYPE

TYPE ST_TestCaseResult :
STRUCT
    sName : STRING(127);
    eState : E_TestState;
    udiAssertions : UDINT;
    udiPassed : UDINT;
    udiFailed : UDINT;
    sErrorMessage : STRING(255);
END_STRUCT
END_TYPE

GVL GVL_TestResults
VAR_GLOBAL
    xStartTests : BOOL;
    xAllDone : BOOL;
    xAnyFailed : BOOL;
    udiFailed : UDINT;
END_VAR
END_GVL

INTERFACE I_TestCase
METHOD PUBLIC m_stGetResult : ST_TestCaseResult
END_METHOD
END_INTERFACE

FUNCTION_BLOCK ABSTRACT FB_TestCaseBase IMPLEMENTS I_TestCase
END_FUNCTION_BLOCK

FUNCTION_BLOCK FB_TestRunner
END_FUNCTION_BLOCK

FUNCTION_BLOCK FB_LimitCounter
VAR_INPUT
    i_xReset : BOOL;
    i_xEnable : BOOL;
    i_nLimit : DINT;
END_VAR
VAR_OUTPUT
    q_nCount : DINT;
END_VAR
IF i_xReset THEN
    q_nCount := 0;
ELSIF i_xEnable THEN
    q_nCount := q_nCount + 1;
END_IF
END_FUNCTION_BLOCK

FUNCTION_BLOCK FB_Test_LimitCounter EXTENDS FB_TestCaseBase
VAR
    fbCut : FB_LimitCounter;
END_VAR
METHOD PUBLIC m_xExecute : BOOL
VAR_INPUT
    i_xTrigger : BOOL;
END_VAR
IF i_xTrigger THEN
    _sTestCaseName := 'FB_LimitCounter clamps at max';
    _eState := eTestState_Running;
    _eExecuteState := eTestState_Running;
    fbCut(i_xReset := TRUE, i_xEnable := FALSE, i_nLimit := 3);
    fbCut(i_xReset := FALSE, i_xEnable := TRUE, i_nLimit := 3);
    m_xAssertEqualDint(1, fbCut.q_nCount, 'first count should be 1');
    fbCut(i_xReset := FALSE, i_xEnable := TRUE, i_nLimit := 3);
    m_xAssertEqualDint(2, fbCut.q_nCount, 'second count should be 2');
    fbCut(i_xReset := FALSE, i_xEnable := TRUE, i_nLimit := 3);
    m_xAssertEqualDint(3, fbCut.q_nCount, 'third count should be 3');
    fbCut(i_xReset := FALSE, i_xEnable := TRUE, i_nLimit := 3);
    m_xAssertEqualDint(3, fbCut.q_nCount, 'counter should clamp at limit');
    _eState := eTestState_Passed;
    _eExecuteState := eTestState_Passed;
    _xPhaseBusy := FALSE;
END_IF
m_xExecute := TRUE;
END_METHOD
END_FUNCTION_BLOCK

PROGRAM MAIN
VAR
    fbRunner : FB_TestRunner;
    fbTest : FB_Test_LimitCounter;
    itfTest : I_TestCase := fbTest;
    _xInitDone : BOOL := FALSE;
END_VAR
IF NOT _xInitDone THEN
    fbRunner.m_udiRegisterTest(itfTest);
    _xInitDone := TRUE;
END_IF
fbRunner();
END_PROGRAM
